#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N, D; scanf("%d %d", &N, &D);
        int risk = 0, age;
        for(int i=0;i<N;i++){
            scanf("%d", &age);
            if(age <= 9 || age >= 80) risk++;
        }
        int nonrisk = N - risk;
        int days = (risk + D - 1) / D + (nonrisk + D - 1) / D;
        printf("%d\n", days);
    }
    return 0;
}

