#!/usr/bin/env python3
import sys

def solve():
    data = list(map(int, sys.stdin.read().strip().split()))
    if not data:
        return
    it = iter(data)
    T = next(it)
    out_lines = []
    for _ in range(T):
        N = next(it); D = next(it)
        risk = 0
        for _ in range(N):
            age = next(it)
            if age <= 9 or age >= 80:
                risk += 1
        nonrisk = N - risk
        days = (risk + D - 1) // D + (nonrisk + D - 1) // D
        out_lines.append(str(days))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

